#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum SafetyField {
    Category,
    Name,
    Reaction,
    Severity,
    Dose,
    Route,
    Frequency,
    Status,
    RecordedDate,
    Notes,
}

impl SafetyField {
    const ALL: [Self; 10] = [
        Self::Category,
        Self::Name,
        Self::Reaction,
        Self::Severity,
        Self::Dose,
        Self::Route,
        Self::Frequency,
        Self::Status,
        Self::RecordedDate,
        Self::Notes,
    ];

    fn label(self) -> &'static str {
        match self {
            Self::Category => "Category",
            Self::Name => "Name",
            Self::Reaction => "Reaction",
            Self::Severity => "Severity",
            Self::Dose => "Dose",
            Self::Route => "Route",
            Self::Frequency => "Frequency",
            Self::Status => "Status",
            Self::RecordedDate => "Date",
            Self::Notes => "Notes",
        }
    }

    fn index(self) -> usize {
        Self::ALL
            .iter()
            .position(|field| *field == self)
            .unwrap_or(0)
    }

    fn next(self) -> Self {
        Self::ALL[(self.index() + 1) % Self::ALL.len()]
    }

    fn previous(self) -> Self {
        let index = self.index();
        Self::ALL[(index + Self::ALL.len() - 1) % Self::ALL.len()]
    }
}

