        let mut lines = vec![workflow_section_line(
            MedicalWorkflowSection::Timeline,
            self.workflow_section,
            "Timeline",
            None,
        )];
        lines.extend(self.workflow_active_action_lines(MedicalWorkflowSection::Timeline));
