        dashboard.handle_key_event(KeyEvent::from(KeyCode::Char(':')));
        for c in "proposal".chars() {
            dashboard.handle_key_event(KeyEvent::from(KeyCode::Char(c)));
        }
        assert_eq!(dashboard.command_selection_index, 0);

